28	fn file_loader_hook(filename: &[u8]) -> Result<Vec<u8>, LuaError> {
29	    #[cfg(unix)]
30	    let path: std::path::PathBuf = {
31	        use std::os::unix::ffi::OsStrExt;
32	        std::path::PathBuf::from(std::ffi::OsStr::from_bytes(filename))
33	    };
34	    #[cfg(not(unix))]
35	    let path: std::path::PathBuf = {
36	        let s = std::str::from_utf8(filename).map_err(|_| {
37	            LuaError::runtime(format_args!("filename is not valid UTF-8"))
38	        })?;
39	        std::path::PathBuf::from(s)
40	    };
41	    std::fs::read(&path).map_err(|err| {
42	        LuaError::runtime(format_args!(
43	            "cannot open '{}': {}",
44	            String::from_utf8_lossy(filename),
45	            err
46	        ))
47	    })
48	}
49	
50	/// `std::fs::File`-backed implementation of [`LuaFileHandle`].
51	///
52	/// Wraps a `BufReader` for read paths and a `BufWriter` for write paths,
53	/// sharing the same underlying `std::fs::File` via cloning the handle.
54	/// The write wrapper is flushed on `Drop` (implicit close) so data is not
55	/// lost when `io.close()` drops the `Box<dyn LuaFileHandle>`.
56	enum FsFile {
57	    Read(BufReader<std::fs::File>),
58	    Write(BufWriter<std::fs::File>),
59	    ReadWrite(std::fs::File, Option<u8>),
60	}
61	
62	impl FsFile {
63	    fn open(filename: &[u8], mode: &[u8]) -> io::Result<Self> {
64	        #[cfg(unix)]
65	        let path: std::path::PathBuf = {
66	            use std::os::unix::ffi::OsStrExt;
67	            std::path::PathBuf::from(std::ffi::OsStr::from_bytes(filename))
68	        };
69	        #[cfg(not(unix))]
70	        let path: std::path::PathBuf = {
71	            let s = std::str::from_utf8(filename)
72	                .map_err(|_| io::Error::new(io::ErrorKind::InvalidInput, "filename not valid UTF-8"))?;
73	            std::path::PathBuf::from(s)
74	        };
75	
76	        let first = mode.first().copied().unwrap_or(b'r');
77	        let update = mode.get(1).copied() == Some(b'+');
78	
79	        if first != b'r' {
80	            if let Some(parent) = path.parent() {
81	                if !parent.as_os_str().is_empty() {
82	                    let _ = std::fs::create_dir_all(parent);
83	                }
84	            }
85	        }
86	
87	        match (first, update) {
88	            (b'r', false) => {
89	                let f = std::fs::File::open(&path)?;
90	                Ok(FsFile::Read(BufReader::new(f)))
91	            }
92	            (b'w', false) => {
93	                let f = std::fs::File::create(&path)?;
94	                Ok(FsFile::Write(BufWriter::new(f)))
95	            }
96	            (b'a', false) => {
97	                let mut f = std::fs::OpenOptions::new().append(true).create(true).open(&path)?;
98	                f.seek(SeekFrom::End(0))?;
99	                Ok(FsFile::Write(BufWriter::new(f)))
100	            }
101	            _ => {
102	                let f = std::fs::OpenOptions::new()
103	                    .read(true)
104	                    .write(true)
105	                    .create(first == b'w' || first == b'a')
106	                    .truncate(first == b'w')
107	                    .append(first == b'a')
108	                    .open(&path)?;
109	                Ok(FsFile::ReadWrite(f, None))
110	            }
111	        }
112	    }
113	}
114	
115	impl LuaFileHandle for FsFile {
116	    fn read_byte(&mut self) -> i32 {
117	        match self {
118	            FsFile::Read(r) => {
119	                let mut buf = [0u8; 1];
120	                match r.read(&mut buf) {
121	                    Ok(1) => buf[0] as i32,
122	                    _ => -1,
123	                }
124	            }
125	            FsFile::ReadWrite(f, pushback) => {
126	                if let Some(b) = pushback.take() {
127	                    return b as i32;
128	                }
129	                let mut buf = [0u8; 1];
130	                match f.read(&mut buf) {
131	                    Ok(1) => buf[0] as i32,
132	                    _ => -1,
133	                }
134	            }
135	            FsFile::Write(_) => -1,
136	        }
137	    }
138	
139	    fn unread_byte(&mut self, byte: i32) {
140	        match self {
141	            FsFile::Read(r) => {
142	                if byte >= 0 {
143	                    let _ = r.seek_relative(-1);
144	                }
145	            }
146	            FsFile::ReadWrite(_, pushback) => {
147	                if byte >= 0 {
148	                    *pushback = Some(byte as u8);
149	                }
150	            }
151	            FsFile::Write(_) => {}
152	        }
153	    }
154	
155	    fn write_bytes(&mut self, data: &[u8]) -> io::Result<usize> {
156	        match self {
157	            FsFile::Write(w) => w.write(data),
158	            FsFile::ReadWrite(f, _) => f.write(data),
159	            FsFile::Read(_) => Err(io::Error::new(io::ErrorKind::PermissionDenied, "file not open for writing")),
160	        }
161	    }
162	
163	    fn flush(&mut self) -> io::Result<()> {
164	        match self {
165	            FsFile::Write(w) => w.flush(),
166	            FsFile::ReadWrite(f, _) => f.flush(),
167	            FsFile::Read(_) => Ok(()),
168	        }
169	    }
170	
171	    fn seek(&mut self, pos: SeekFrom) -> io::Result<u64> {
172	        match self {
173	            FsFile::Read(r) => r.seek(pos),
174	            FsFile::Write(w) => w.seek(pos),
175	            FsFile::ReadWrite(f, _) => f.seek(pos),
176	        }
177	    }
178	
179	    fn tell(&mut self) -> io::Result<u64> {
180	        self.seek(SeekFrom::Current(0))
181	    }
182	
183	    fn clear_error(&mut self) {}
184	
185	    fn has_error(&self) -> bool { false }
186	}
187	
188	impl Drop for FsFile {
189	    fn drop(&mut self) {
190	        if let FsFile::Write(w) = self {
191	            let _ = w.flush();
192	        }
193	    }
194	}
