196	fn file_remove_hook(filename: &[u8]) -> Result<(), LuaError> {
197	    #[cfg(unix)]
198	    let path: std::path::PathBuf = {
199	        use std::os::unix::ffi::OsStrExt;
200	        std::path::PathBuf::from(std::ffi::OsStr::from_bytes(filename))
201	    };
202	    #[cfg(not(unix))]
203	    let path: std::path::PathBuf = {
204	        let s = std::str::from_utf8(filename).map_err(|_| {
205	            LuaError::runtime(format_args!("filename is not valid UTF-8"))
206	        })?;
207	        std::path::PathBuf::from(s)
208	    };
209	    std::fs::remove_file(&path)
210	        .or_else(|_| std::fs::remove_dir(&path))
211	        .map_err(|err| {
212	            LuaError::runtime(format_args!(
213	                "cannot remove '{}': {}",
214	                String::from_utf8_lossy(filename),
215	                err
216	            ))
217	        })
218	}
219	
220	fn file_open_hook(filename: &[u8], mode: &[u8]) -> Result<Box<dyn LuaFileHandle>, LuaError> {
221	    FsFile::open(filename, mode).map(|f| Box::new(f) as Box<dyn LuaFileHandle>).map_err(|err| {
222	        LuaError::runtime(format_args!(
223	            "cannot open '{}': {}",
224	            String::from_utf8_lossy(filename),
225	            err
226	        ))
227	    })
228	}
229	
230	fn parser_hook(
231	    state: &mut LuaState,
232	    source: &[u8],
233	    name: &[u8],
234	    firstchar: i32,
235	) -> Result<GcRef<LuaLClosure>, LuaError> {
236	    let proto = lua_parse::parse(
237	        state,
238	        lua_parse::DynData::default(),
239	        source,
240	        name,
241	        firstchar,
242	    )?;
243	    let nupvals = proto.upvalues.len();
244	    let mut upvals = Vec::with_capacity(nupvals);
245	    for _ in 0..nupvals {
246	        upvals.push(std::cell::RefCell::new(GcRef::new(UpVal::closed(LuaValue::Nil))));
247	    }
248	    Ok(GcRef::new(LuaLClosure {
249	        proto: GcRef::new(*proto),
250	        upvals,
251	    }))
252	}
253	
254	const MULTRET: i32 = -1;
255	
256	fn render_lua_error(e: &LuaError) -> String {
257	    match e {
258	        LuaError::Runtime(v) | LuaError::Syntax(v) => match v {
259	            LuaValue::Str(s) => format!("{}: {}", e_tag(e), String::from_utf8_lossy(s.as_bytes())),
260	            other => format!("{}: {:?}", e_tag(e), other),
261	        },
262	        LuaError::Memory | LuaError::Error | LuaError::Yield
263	        | LuaError::File | LuaError::Gc => format!("{}", e_tag(e)),
264	    }
265	}
266	
267	fn e_tag(e: &LuaError) -> &'static str {
268	    match e {
269	        LuaError::Runtime(_) => "Runtime",
270	        LuaError::Syntax(_)  => "Syntax",
271	        LuaError::Memory     => "Memory",
272	        LuaError::Error      => "Error",
273	        LuaError::Yield      => "Yield",
274	        LuaError::File       => "File",
275	        LuaError::Gc         => "Gc",
276	    }
277	}
278	
279	#[cfg(unix)]
280	fn os_str_bytes(s: &std::ffi::OsString) -> Vec<u8> {
281	    use std::os::unix::ffi::OsStrExt;
282	    s.as_bytes().to_vec()
283	}
284	#[cfg(not(unix))]
285	fn os_str_bytes(s: &std::ffi::OsString) -> Vec<u8> {
286	    s.to_string_lossy().into_owned().into_bytes()
287	}
288	
289	fn main() -> ExitCode {
290	    let args_os: Vec<std::ffi::OsString> = std::env::args_os().collect();
291	    if args_os.len() < 2 {
292	        let prog = args_os
293	            .first()
294	            .map(|s| s.to_string_lossy().into_owned())
295	            .unwrap_or_else(|| "lua-rs".to_string());
296	        eprintln!("usage: {prog} <script.lua | -e 'source'>");
297	        eprintln!("examples:");
298	        eprintln!("  {prog} script.lua");
299	        eprintln!("  {prog} -e 'print(\"hello\")'");
300	        return ExitCode::from(2);
301	    }
302	
303	    let source: Vec<u8> = if args_os[1] == "-e" {
304	        if args_os.len() < 3 {
305	            eprintln!("-e requires an argument");
306	            return ExitCode::from(2);
307	        }
308	        os_str_bytes(&args_os[2])
309	    } else {
310	        let path = std::path::Path::new(&args_os[1]);
311	        if path.is_file() {
312	            match std::fs::read(path) {
313	                Ok(bytes) => bytes,
314	                Err(e) => {
315	                    eprintln!("cannot read {}: {}", path.display(), e);
316	                    return ExitCode::from(2);
317	                }
318	            }
319	        } else {
320	            os_str_bytes(&args_os[1])
321	        }
322	    };
323	
324	    let verbose = std::env::var("LUA_RS_VERBOSE").is_ok();
325	    macro_rules! step { ($($t:tt)*) => { if verbose { eprintln!($($t)*); } }; }
326	
327	    step!("[1/4] Creating LuaState...");
328	    let result = catch_unwind(AssertUnwindSafe(|| {
329	        let mut state = new_state().ok_or("new_state returned None")?;
330	        state.global_mut().parser_hook = Some(parser_hook);
331	        state.global_mut().file_loader_hook = Some(file_loader_hook);
332	        state.global_mut().file_open_hook = Some(file_open_hook);
333	        state.global_mut().file_remove_hook = Some(file_remove_hook);
334	
335	        step!("[2/4] Opening standard library...");
336	        open_libs(&mut state).map_err(|e| format!("open_libs failed: {}", render_lua_error(&e)))?;
337	
338	        step!("[3/4] Loading source (parse + compile)...");
339	        let status = load_string(&mut state, &source)
340	            .map_err(|e| format!("load_string failed: {}", render_lua_error(&e)))?;
341	        if status != 0 {
342	            let msg = match to_lua_string(&mut state, -1) {
343	                Ok(Some(s)) => String::from_utf8_lossy(s.as_bytes()).into_owned(),
344	                _ => "(no error message on stack)".to_string(),
345	            };
346	            return Err(format!(
347	                "Syntax: {} (load_string status={})",
348	                msg, status
349	            ));
350	        }
351	
352	        step!("[4/4] Executing chunk...");
353	        let final_status = pcall_k(&mut state, 0, MULTRET, 0, 0, None)
354	            .map_err(|e| format!("pcall_k failed: {}", render_lua_error(&e)))?;
355	
356	        Ok::<_, String>(final_status)
357	    }));
358	
359	    match result {
360	        Ok(Ok(status)) => {
361	            if verbose {
362	                eprintln!("[ok] execution completed, status={:?}", status);
363	            }
364	            let _ = status;
365	            ExitCode::SUCCESS
366	        }
367	        Ok(Err(msg)) => {
368	            eprintln!("lua: {}", msg);
369	            ExitCode::from(1)
370	        }
371	        Err(panic) => {
372	            let msg = if let Some(s) = panic.downcast_ref::<String>() {
373	                s.clone()
374	            } else if let Some(s) = panic.downcast_ref::<&str>() {
375	                s.to_string()
376	            } else {
377	                "(non-string panic payload)".to_string()
378	            };
379	            eprintln!("[panic] {}", msg);
380	            ExitCode::from(101)
381	        }
382	    }
383	}
384	
385	// ──────────────────────────────────────────────────────────────────────────
386	// PORT STATUS
387	//   source:        (minimal entrypoint; not a port of lua.c — that's Phase F)
388	//   target_crate:  lua-cli
389	//   confidence:    high
390	//   todos:         0
391	//   port_notes:    0
392	//   unsafe_blocks: 0
393	//   notes:         drives new_state → open_libs → load_string → pcall_k.
394	//                  Designed to surface the first todo!() panic on a hello-
395	//                  world program, not to be a complete interpreter.
396	// ──────────────────────────────────────────────────────────────────────────
