    fn opt_arg_lstring(&mut self, arg: i32, def: Option<&[u8]>) -> Result<Option<Vec<u8>>, LuaError> {
        match lua_vm::api::lua_type_at(self, arg) {
            LuaType::None | LuaType::Nil => Ok(def.map(|d| d.to_vec())),
